it('routes input containing @ to email validation and accepts a valid address', () => {
  expect(validateEmailOrUsername('user@example.com')).toBe(true);
});

it('routes plain text input to username validation and accepts a clean username', () => {
  expect(validateEmailOrUsername('john_doe')).toBe(true);
});

it('returns an error message when the email format is invalid via EMAIL_REGEX', () => {
  expect(validateEmailOrUsername('bad@email.org')).toBe(INVALID_EMAIL);
});

it('returns an error message when the username contains special characters', () => {
  expect(validateEmailOrUsername('bad user!')).toBe(INVALID_USERNAME);
});

it('returns false when no token is stored', () => {
  expect(isUserLoggedIn()).toBe(false);
});

it('returns true after a token has been stored under storageKeys.token', () => {
  appStorage.set(storageKeys.token, 'abc-token-123');
  expect(isUserLoggedIn()).toBe(true);
});

it('saves the access token to localStorage under the TOKEN key', () => {
  updateNewTokenDetails({ loginTime: '2024-01-01', token: 'my-token', refreshToken: 'my-refresh' });
  expect(appStorage.get(storageKeys.token)).toBe('my-token');
});

it('saves the refresh token under the REFRESHTOKEN key', () => {
  updateNewTokenDetails({ loginTime: '2024-01-01', token: 'tok', refreshToken: 'ref-tok' });
  expect(appStorage.get(storageKeys.refreshToken)).toBe('ref-tok');
});

it('saves the login time under the LOGGEDINTIME key', () => {
  updateNewTokenDetails({ loginTime: '2024-06-15T10:00:00Z', token: 't', refreshToken: 'r' });
  expect(appStorage.get(storageKeys.loginTime)).toBe('2024-06-15T10:00:00Z');
});

it('output of generateCardNumber preserves first and last 4 digits', () => {
  // Use count=8 so fullNumber is 16 chars → splits cleanly as 4+4+4+4
  // '4111' + 'XXXXXXXX' + '1111' → '4111 XXXX XXXX 1111'
  const result = generateCardNumber('4111', '1111', 8);
  expect(result).toContain('4111');
  expect(result).toContain('1111');
  expect(result).toContain('X');
});

it('correctly masks middle digits with X characters', () => {
  const result = generateCardNumber('4111', '1111', 8);
  expect(result).toContain('XXXX');
  expect(result).toContain('4111');
  expect(result).toContain('1111');
});

it('capitalizes the first letter of each word in a multi-word string', () => {
  // The function capitalizes every word's first letter via split/map
  expect(capitalizeFirstLetter('john doe')).toBe('John Doe');
});

it('capitalizes a single word correctly without whitespace branch', () => {
  expect(capitalizeFirstLetter('alice')).toBe('Alice');
});

it('returns undefined when given a non-string truthy value after type guard fix', () => {
  expect(capitalizeFirstLetter(123)).toBeUndefined();
});

it('populates userCards in state after dispatch', () => {
  const cards  = [{ id: '1', last4: '1111' }];
  const action = updateUserCards(cards, true);
  const state  = paymentReducer(undefined, action);
  expect(state.userCards).toEqual(cards);
});

it('sets cardsFetched to true when cards are provided', () => {
  const action = updateUserCards([{ id: '2' }], true);
  const state  = paymentReducer(undefined, action);
  expect(state.cardsFetched).toBe(true);
});

it('clears userCards when dispatched with an empty array', () => {
  const filled  = paymentReducer(undefined, updateUserCards([{ id: '1' }], true));
  const cleared = paymentReducer(filled, updateUserCards([], false));
  expect(cleared.userCards).toEqual([]);
  expect(cleared.cardsFetched).toBe(false);
});

it('stores the subscription plan object in paymentPlantDetails', () => {
  const plan   = { id: 'plan-1', name: 'Premium', price: 9.99 };
  const action = updatePaymentPlanDetails(plan);
  const state  = paymentReducer(undefined, action);
  expect(state.paymentPlantDetails).toEqual(plan);
});

it('does not mutate userCards when a plan update is dispatched', () => {
  const withCards = paymentReducer(undefined, updateUserCards([{ id: 'c1' }], true));
  const withPlan  = paymentReducer(withCards, updatePaymentPlanDetails({ id: 'p1' }));
  expect(withPlan.userCards).toEqual([{ id: 'c1' }]);
});

it('resets userCards to an empty array', () => {
  const loaded  = paymentReducer(undefined, updateUserCards([{ id: '1' }], true));
  const cleared = paymentReducer(loaded, { type: paymentActions.CLEARCARDS });
  expect(cleared.userCards).toEqual([]);
});

it('resets cardsFetched back to false after clearing', () => {
  const loaded  = paymentReducer(undefined, updateUserCards([{ id: '1' }], true));
  const cleared = paymentReducer(loaded, { type: paymentActions.CLEARCARDS });
  expect(cleared.cardsFetched).toBe(false);
});

it('storageKeys.stripePaymentDetails equals STRIPEPAYMENTDETAILS', () => {
  expect(storageKeys.stripePaymentDetails).toBe('STRIPEPAYMENTDETAILS');
});

it('storageKeys.token equals TOKEN', () => {
  expect(storageKeys.token).toBe('TOKEN');
});

it('accepts a standard 19-character card number with spaces', () => {
  // 19 chars: "4111 1111 1111 1111" (4+1+4+1+4+1+4 = 19)
  expect(CARD_NUMBER_REGEX.test('4111 1111 1111 1111')).toBe(true);
});

it('rejects a card number shorter than 17 characters', () => {
  expect(CARD_NUMBER_REGEX.test('4111 1111 1111')).toBe(false);
});

it('rejects a card number that contains letters', () => {
  expect(CARD_NUMBER_REGEX.test('4111 ABCD 1111 1111 ')).toBe(false);
});

it('addCard points to the correct payment creation path', () => {
  expect(endpoints.payment.addCard).toBe('/api/v2/payments/me?');
});

it('getAllCards points to the cards listing path', () => {
  expect(endpoints.payment.getAllCards).toBe('/api/v2/payments/me');
});

it('paymentsCheckout points to the checkout path', () => {
  expect(endpoints.payment.paymentsCheckout).toBe('/api/v2/payments/checkout');
});

it('addCardtoFavourite endpoint points to sports favourites add path', () => {
  expect(endpoints.favourites.addCardtoFavourite).toBe(
    '/api/v1/client/sports/add-favorite-match',
  );
});

it('advertisement endpoint builder produces a correctly interpolated URL', () => {
  const url = endpoints.advertisement('vod', '123', 'action');
  expect(url).toContain('type=vod');
  expect(url).toContain('vod_id=123');
  expect(url).toContain('genresId=action');
});

it('MAX_IMAGE_UPLOAD_SIZE equals 10 MB expressed in bytes', () => {
  expect(MAX_IMAGE_UPLOAD_SIZE).toBe(10 * 1024 * 1024);
});

it('TIMEOUT equals 30 seconds expressed in milliseconds', () => {
  expect(TIMEOUT).toBe(30 * 1000);
});

it('starts with an empty userFavourites list', () => {
  const state = favouritesReducer(undefined, { type: '@@INIT' });
  expect(state.userFavourites).toEqual([]);
});

it('UPDATEALLFAVOURITIESDETAILS replaces the favourites list', () => {
  const favs  = [{ id: 'm1' }, { id: 'm2' }];
  const state = favouritesReducer(undefined, {
    type:              favouritesActions.UPDATEALLFAVOURITIESDETAILS,
    userFavourites:    favs,
    favouritesFetched: true,
  });
  expect(state.userFavourites).toEqual(favs);
});

it('sets favouritesFetched to true once the list is loaded', () => {
  const state = favouritesReducer(undefined, {
    type:              favouritesActions.UPDATEALLFAVOURITIESDETAILS,
    userFavourites:    [{ id: 'm1' }],
    favouritesFetched: true,
  });
  expect(state.favouritesFetched).toBe(true);
});

it('returns unchanged state for an unknown action', () => {
  const before = favouritesReducer(undefined, { type: '@@INIT' });
  const after  = favouritesReducer(before, { type: 'RANDOM_ACTION' });
  expect(after).toEqual(before);
});

it('initialises with showToast as null', () => {
  const state = toastReducer(undefined, { type: '@@INIT' });
  expect(state.showToast).toBeNull();
});

it('TOAST action stores the toast message in showToast', () => {
  const state = toastReducer(undefined, {
    type:  TOAST,
    toast: { message: 'Card added successfully', type: 'success' },
  });
  expect(state.showToast.message).toBe('Card added successfully');
});

it('resets showToast to null when null is dispatched', () => {
  const withToast    = toastReducer(undefined, { type: TOAST, toast: { message: 'hi' } });
  const withoutToast = toastReducer(withToast,  { type: TOAST, toast: null });
  expect(withoutToast.showToast).toBeNull();
});

it('returns unchanged state for an unknown action', () => {
  const before = toastReducer(undefined, { type: '@@INIT' });
  const after  = toastReducer(before, { type: 'UNKNOWN_TOAST_ACTION' });
  expect(after).toEqual(before);
});

it('initialises with data as an empty array', () => {
  const state = userDetailsReducer(undefined, { type: '@@INIT' });
  expect(state.data).toEqual([]);
});

it('SUCCESS action populates data and token from the payload', () => {
  // The reducer reads action.data.profile/.token etc — so data must be an object
  const data  = { token: 'tok-123', profile: 'p1', profiles: [], device: 'd1' };
  const state = userDetailsReducer(undefined, { type: SUCCESS, data });
  expect(state.token).toBe('tok-123');
});

it('UPDATEREFRESHEDTOKEN updates token and loginTime independently', () => {
  const state = userDetailsReducer(undefined, {
    type: UPDATEREFRESHEDTOKEN,
    payload: { token: 'new-tok', loginTime: 1700000000000, refreshToken: 'ref' },
  });
  expect(state.token).toBe('new-tok');
  expect(state.loginTime).toBe(1700000000000);
});

it('ONAUTHENTICATE resets profileAuthSuccess to false', () => {
  const withAuth = userDetailsReducer(undefined, {
    type: SUCCESS,
    data: [], token: 't', device: 'd', profile: [], profiles: [], authSuccess: true,
  });
  const reset    = userDetailsReducer(withAuth, { type: ONAUTHENTICATE });
  expect(reset.profileAuthSuccess).toBe(false);
});

it('SHOWLOGGEDOUTSHEET stores the payload in showLoggedOutSheet', () => {
  const state = userDetailsReducer(undefined, {
    type: SHOWLOGGEDOUTSHEET, payload: true,
  });
  expect(state.showLoggedOutSheet).toBe(true);
});

it('returns unchanged state for an unknown action type', () => {
  const before = userDetailsReducer(undefined, { type: '@@INIT' });
  const after  = userDetailsReducer(before,    { type: 'UNKNOWN_ACTION' });
  expect(after).toEqual(before);
});

it('initialises with an empty profileData array', () => {
  const state = profileReducer(undefined, { type: '@@INIT' });
  expect(state.profileData).toEqual([]);
});

it('PROFILESDETAILS action replaces profileData with the new list', () => {
  const profiles = [{ id: 'p1', name: 'Alice' }, { id: 'p2', name: 'Bob' }];
  const state    = profileReducer(undefined, { type: PROFILESDETAILS, data: profiles });
  expect(state.profileData).toEqual(profiles);
});

it('SAVESELECTEDPROFILEDETAILS stores the chosen profile', () => {
  const selected = { id: 'p1', name: 'Alice' };
  const state    = profileReducer(undefined, { type: SAVESELECTEDPROFILEDETAILS, data: selected });
  expect(state.selectedProfileDetails).toEqual(selected);
});

it('returns current state unchanged for an unrecognised action', () => {
  const before = profileReducer(undefined, { type: '@@INIT' });
  const after  = profileReducer(before,    { type: 'NO_SUCH_ACTION' });
  expect(after).toEqual(before);
});

it('accepts a valid .com email address', () => {
  expect(EMAIL_REGEX.test('user@example.com')).toBe(true);
});

it('rejects an email address missing the @ symbol', () => {
  expect(EMAIL_REGEX.test('userexample.com')).toBe(false);
});

it('rejects a non-.com domain (e.g. .org)', () => {
  expect(EMAIL_REGEX.test('user@example.org')).toBe(false);
});

it('accepts a password meeting all requirements', () => {
  expect(PASSWORD_REGEX_CHANGE_PASSWORD.test('Secure@1pass')).toBe(true);
});

it('rejects a password without an uppercase letter', () => {
  expect(PASSWORD_REGEX_CHANGE_PASSWORD.test('secure@1pass')).toBe(false);
});

it('rejects a password without a special character', () => {
  expect(PASSWORD_REGEX_CHANGE_PASSWORD.test('Secure1pass')).toBe(false);
});

it('rejects a password longer than 30 characters', () => {
  expect(PASSWORD_REGEX_CHANGE_PASSWORD.test('Secure@1pass' + 'x'.repeat(20))).toBe(false);
});

it('accepts a string of digits and spaces', () => {
  expect(CARD_REGEX.test('4111 1111 1111 1111')).toBe(true);
});

it('rejects letters inside a card number', () => {
  expect(CARD_REGEX.test('4111 ABCD 1111 1111')).toBe(false);
});

it('accepts a 10-digit phone number', () => {
  expect(PHONE_REGEX.test('9876543210')).toBe(true);
});

it('accepts a phone number with a + country prefix', () => {
  expect(PHONE_REGEX.test('+919876543210')).toBe(true);
});

it('rejects a phone number shorter than 10 digits', () => {
  expect(PHONE_REGEX.test('98765')).toBe(false);
});

it('accepts a valid alphanumeric username with a letter', () => {
  expect(UNIQUE_USERNAME_REGEX.test('john_doe42')).toBe(true);
});

it('rejects a username made entirely of digits', () => {
  expect(UNIQUE_USERNAME_REGEX.test('123456')).toBe(false);
});

it('accepts a properly spaced 19-character card number', () => {
  // 19 chars: "4111 1111 1111 1111" (4+1+4+1+4+1+4 = 19)
  expect(CARD_NUMBER_REGEX.test('4111 1111 1111 1111')).toBe(true);
});

it('rejects a card number shorter than 17 characters', () => {
  expect(CARD_NUMBER_REGEX.test('4111 1111 1111')).toBe(false);
});

it('returns an empty string when the value is null', () => {
  expect(checkNull(null)).toBe('');
});

it('returns the original value when it is defined and non-null', () => {
  expect(checkNull('hello')).toBe('hello');
});

it('returns an empty array when the input is null', () => {
  expect(checkArray(null)).toEqual([]);
});

it('returns the original array when it contains items', () => {
  expect(checkArray([1, 2, 3])).toEqual([1, 2, 3]);
});

it('returns true for a string that contains a space', () => {
  expect(checkWhiteSpace('hello world')).toBe(true);
});

it('returns false for a string with no whitespace', () => {
  expect(checkWhiteSpace('helloworld')).toBe(false);
});

it('correctly parses 3661 seconds into 1h 01m 01s', () => {
  const [h, m, s, formatted] = getTimes(3661);
  expect(h).toBe(1);
  expect(m).toBe(1);
  expect(s).toBe(1);
  expect(formatted).toBe('1:01:01');
});

it('returns 0 hours when the duration is under 3600 seconds', () => {
  const [h] = getTimes(120);
  expect(h).toBe(0);
});

it('calculates 50% when value is half of max', () => {
  expect(getProgressWidth(50, 100)).toBe(50);
});

it('returns 0 when the value argument is missing or falsy', () => {
  expect(getProgressWidth(0, 100)).toBe(0);
});
